I suspect the issue is here: https://github.com/containers/libpod/blob/b2200dbe056ac409461033f646cdd25bcccea521/libpod/container_log.go#L64

It should say:

			if nll.Partial() {
				partial += nll.Msg
				continue
			} else if !nll.Partial() && len(partial) > 1 {
				nll.Msg = partial + nll.Msg
				partial = ""
			}
